impl From<u16> for Swift {
    #[inline(always)]
    fn from(x: u16) -> Self {
        num::FromPrimitive::from_u16(x).unwrap_or(Self::Error)
    }
}

// Swift == u16
impl PartialEq<u16> for Swift {
    #[inline(always)]
    fn eq(&self, x: &u16) -> bool {
        *self == Into::<Self>::into(*x)
    }
}

// u16 == Swift
impl PartialEq<Swift> for u16 {
    #[inline(always)]
    fn eq(&self, x: &Swift) -> bool {
        *x == *self
    }
}
